import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Search, Globe } from 'lucide-react';
import { dbSimulador } from '../services/dbSimulador';

const PanelCliente = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  
  const [provinciaSel, setProvinciaSel] = useState('Tucumán');
  const [ciudadSel, setCiudadSel] = useState('Todas');
  const [zonaSel, setZonaSel] = useState('Todas las zonas');

  // Carga inicial desde el simulador
  useEffect(() => {
    setTodasLasOfertas(dbSimulador.getOfertasGlobales());
  }, []);

  // Lógica de filtrado jerárquico
  useEffect(() => {
    const filtrado = todasLasOfertas.filter(o => {
      const matchBusqueda = o.producto.toLowerCase().includes(busqueda.toLowerCase());
      const matchProv = o.provincia === provinciaSel;
      const matchCiudad = ciudadSel === 'Todas' || o.ciudad === ciudadSel;
      const matchZona = zonaSel === 'Todas las zonas' || o.zona === zonaSel;
      return matchBusqueda && matchProv && matchCiudad && matchZona;
    });
    setOfertasFiltradas(filtrado);
  }, [busqueda, provinciaSel, ciudadSel, zonaSel, todasLasOfertas]);

  // Listas dinámicas para los selectores
  const ciudadesDisponibles = [...new Set(todasLasOfertas.filter(o => o.provincia === provinciaSel).map(o => o.ciudad))];
  const zonasDisponibles = ['Todas las zonas', ...new Set(todasLasOfertas.filter(o => o.ciudad === ciudadSel || ciudadSel === 'Todas').map(o => o.zona))];

  return (
    <div style={{ background: '#f8fafc', minHeight: '100vh' }}>
      {/* Header de Ubicación */}
      <div style={navStyle}>
        <div style={selectorContainer}>
          <div style={group}>
            <Globe size={16} color="#f97316" />
            <select value={provinciaSel} onChange={(e) => {setProvinciaSel(e.target.value); setCiudadSel('Todas');}} style={selectStyle}>
              <option value="Tucumán">Tucumán</option>
              <option value="Salta">Salta</option>
            </select>
          </div>
          <div style={divider} />
          <div style={group}>
            <MapPin size={16} color="#f97316" />
            <select value={ciudadSel} onChange={(e) => setCiudadSel(e.target.value)} style={selectStyle}>
              <option value="Todas">Todas las ciudades</option>
              {ciudadesDisponibles.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
        </div>
        
        <div style={tabContainer}>
          {zonasDisponibles.map(z => (
            <button key={z} onClick={() => setZonaSel(z)} style={zonaSel === z ? tabActive : tabStyle}>{z}</button>
          ))}
        </div>
      </div>

      <div style={{ padding: '20px 5%' }}>
        {/* Buscador Global */}
        <div style={searchBar}>
          <Search size={20} color="#94a3b8" />
          <input 
            placeholder="Buscar por producto (ej: Aceite, Leche...)" 
            style={inputStyle}
            onChange={(e) => setBusqueda(e.target.value)}
          />
        </div>

        {/* Resultados */}
        <div style={grid}>
          {ofertasFiltradas.map(o => (
            <div key={o.id} style={card}>
              <div style={badge}>Oferta</div>
              <div style={{ padding: '20px' }}>
                <span style={localLabel}>{o.nombreLocal}</span>
                <h3 style={title}>{o.producto}</h3>
                <p style={address}><MapPin size={12} /> {o.direccionLocal}, {o.zona}</p>
                <div style={priceRow}>
                  <span style={price}>${o.precioNuevo}</span>
                  <span style={oldPrice}>${o.precioViejo}</span>
                </div>
                <button style={btnAction}>Ver en mapa / Reservar</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// Estilos de UI
const navStyle = { background: 'white', padding: '15px 5%', borderBottom: '1px solid #e2e8f0', sticky: 'top' };
const selectorContainer = { display: 'flex', gap: '20px', background: '#f1f5f9', padding: '10px 20px', borderRadius: '30px' };
const group = { display: 'flex', alignItems: 'center', gap: '8px' };
const divider = { width: '1px', background: '#cbd5e1', height: '20px' };
const selectStyle = { border: 'none', background: 'transparent', fontWeight: '600', outline: 'none' };
const tabContainer = { display: 'flex', gap: '10px', marginTop: '15px', overflowX: 'auto' };
const tabStyle = { padding: '8px 15px', borderRadius: '20px', border: '1px solid #e2e8f0', background: 'none', whiteSpace: 'nowrap', cursor: 'pointer' };
const tabActive = { ...tabStyle, background: '#1e293b', color: 'white' };
const searchBar = { display: 'flex', background: 'white', padding: '15px', borderRadius: '15px', border: '1px solid #e2e8f0', marginBottom: '25px' };
const inputStyle = { border: 'none', outline: 'none', flex: 1, marginLeft: '10px', fontSize: '1rem' };
const grid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px' };
const card = { background: 'white', borderRadius: '15px', border: '1px solid #e2e8f0', overflow: 'hidden', position: 'relative' };
const badge = { position: 'absolute', top: '10px', right: '10px', background: '#ef4444', color: 'white', padding: '2px 8px', borderRadius: '5px', fontSize: '0.7rem' };
const localLabel = { fontSize: '0.7rem', color: '#f97316', fontWeight: '800', textTransform: 'uppercase' };
const title = { margin: '5px 0', fontSize: '1.2rem' };
const address = { fontSize: '0.75rem', color: '#64748b', display: 'flex', alignItems: 'center', gap: '4px' };
const priceRow = { display: 'flex', alignItems: 'baseline', gap: '10px', marginTop: '10px' };
const price = { fontSize: '1.5rem', fontWeight: 'bold' };
const oldPrice = { textDecoration: 'line-through', color: '#94a3b8', fontSize: '0.9rem' };
const btnAction = { width: '100%', marginTop: '15px', padding: '10px', borderRadius: '10px', border: 'none', background: '#1e293b', color: 'white', fontWeight: 'bold' };

export default PanelCliente;
